on_write:
let res = #{ action: "Allow" };
if !payload.contains("geometry") {
    res.action = "Reject";
    res.reason = "Spatial Geographic objects require a GeoJSON geometry field";
}
res

on_read:
let res = #{ payload: payload };
// Placeholder for polygon intersection
res.match_found = true;
res

on_index:
let res = #{ score: 1.0 };
if payload.geometry.type == "Point" {
    res.point = payload.geometry.coordinates;
}
res
